const body = $input.item.json.body || $input.item.json;
const { pageUrl, targetKeyword, projectName } = body;

if (!pageUrl || !projectName) {
  throw new Error('Missing required fields: pageUrl, projectName');
}

return [{ json: { pageUrl, targetKeyword, projectName } }];

const newPage = $('Validate Input').item.json;
const existingPages = $input.all().map(i => i.json);

if (existingPages.length === 0) {
  return [{ json: { skip: true, message: 'No existing pages to link from/to' } }];
}

const pageList = existingPages
  .filter(p => p.page_url)
  .map(p => `- URL: ${p.page_url} | Keyword: ${p.target_keyword || 'general'} | Title: ${p.page_title || ''}`)
  .join('\n');

const prompt = `New page target keyword: "${newPage.targetKeyword}"
New page URL: ${newPage.pageUrl}

Existing pages:\n${pageList}

Find:
1. Five (5) most topically relevant existing pages TO LINK TO this new page (they should receive an outgoing link pointing to the new page)
2. Three (3) existing pages that this new page should link FROM (the new page gets an outgoing internal link to them)

Return ONLY a JSON object:
{
  "link_to_new_page": [
    {"page_url": "url", "suggested_anchor_text": "anchor text"}
  ],
  "link_from_new_page": [
    {"page_url": "url", "suggested_anchor_text": "anchor text"}
  ]
}`;

return [{ json: { ...newPage, claudePrompt: prompt, existingPagesCount: existingPages.length } }];

const claudeData = $input.item.json;
const inputData = $('Build Linking Prompt').item.json;

if (inputData.skip) return [{ json: inputData }];

let suggestions = { link_to_new_page: [], link_from_new_page: [] };
try {
  const rawText = claudeData.content?.[0]?.text || '{}';
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  suggestions = jsonMatch ? JSON.parse(jsonMatch[0]) : suggestions;
} catch(e) {
  console.log('Parse error:', e.message);
}

return [{ json: {
  pageUrl: inputData.pageUrl,
  targetKeyword: inputData.targetKeyword,
  projectName: inputData.projectName,
  linkToNewPage: suggestions.link_to_new_page || [],
  linkFromNewPage: suggestions.link_from_new_page || []
}}];

